// TransactionProcessor.java
package com.bank.ws;

import java.util.HashMap;
import java.util.Map;
import java.util.logging.Logger;

public class TransactionProcessor {
    
    private static final Logger logger = Logger.getLogger(TransactionProcessor.class.getName());
    private static final Map<String, Double> accounts = new HashMap<>();
    
    static {
        accounts.put("ACC001", 10000.0);
        accounts.put("ACC002", 5000.0);
        accounts.put("ACC003", 15000.0);
    }
    
    public boolean processTransaction(TransactionRequest request) {
        String accountNumber = request.getAccountNumber();
        double amount = request.getAmount();
        String type = request.getTransactionType();
        
        if (!accounts.containsKey(accountNumber)) {
            logger.warning("Account not found: " + accountNumber);
            return false;
        }
        
        double currentBalance = accounts.get(accountNumber);
        
        if ("DEBIT".equalsIgnoreCase(type)) {
            if (currentBalance >= amount) {
                accounts.put(accountNumber, currentBalance - amount);
                logger.info("Debited " + amount + " from account " + accountNumber);
                return true;
            } else {
                logger.warning("Insufficient funds in account " + accountNumber);
                return false;
            }
        } else if ("CREDIT".equalsIgnoreCase(type)) {
            accounts.put(accountNumber, currentBalance + amount);
            logger.info("Credited " + amount + " to account " + accountNumber);
            return true;
        }
        
        return false;
    }
    
    public double getBalance(String accountNumber) {
        return accounts.getOrDefault(accountNumber, 0.0);
    }
    
    public boolean transferFunds(TransferRequest request) {
        String fromAccount = request.getFromAccount();
        String toAccount = request.getToAccount();
        double amount = request.getAmount();
        
        if (!accounts.containsKey(fromAccount) || !accounts.containsKey(toAccount)) {
            logger.warning("One or both accounts not found");
            return false;
        }
        
        double fromBalance = accounts.get(fromAccount);
        if (fromBalance < amount) {
            logger.warning("Insufficient funds for transfer");
            return false;
        }
        
        accounts.put(fromAccount, fromBalance - amount);
        accounts.put(toAccount, accounts.get(toAccount) + amount);
        
        logger.info("Transferred " + amount + " from " + fromAccount + " to " + toAccount);
        return true;
    }
}

// ServerPasswordCallback.java
package com.bank.ws.security;

import org.apache.wss4j.common.ext.WSPasswordCallback;
import javax.security.auth.callback.Callback;
import javax.security.auth.callback.CallbackHandler;
import javax.security.auth.callback.UnsupportedCallbackException;
import java.io.IOException;

public class ServerPasswordCallback implements CallbackHandler {
    
    @Override
    public void handle(Callback[] callbacks) throws IOException, UnsupportedCallbackException {
        for (Callback callback : callbacks) {
            if (callback instanceof WSPasswordCallback) {
                WSPasswordCallback pc = (WSPasswordCallback) callback;
                
                if ("server".equals(pc.getIdentifier())) {
                    pc.setPassword("serverPassword");
                } else if ("client".equals(pc.getIdentifier())) {
                    pc.setPassword("clientPassword");
                }
            } else {
                throw new UnsupportedCallbackException(callback, "Unrecognized Callback");
            }
        }
    }
}

// SignatureValidationInterceptor.java
package com.bank.ws.security;

import org.apache.cxf.binding.soap.SoapMessage;
import org.apache.cxf.interceptor.Fault;
import org.apache.cxf.phase.AbstractPhaseInterceptor;
import org.apache.cxf.phase.Phase;
import org.apache.cxf.ws.security.wss4j.WSS4JInInterceptor;
import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.NodeList;

import javax.xml.namespace.QName;
import java.util.HashMap;
import java.util.Map;
import java.util.logging.Logger;

public class SignatureValidationInterceptor extends AbstractPhaseInterceptor<SoapMessage> {
    
    private static final Logger logger = Logger.getLogger(SignatureValidationInterceptor.class.getName());
    
    public SignatureValidationInterceptor() {
        super(Phase.PRE_PROTOCOL);
        addAfter(WSS4JInInterceptor.class.getName());
    }
    
    @Override
    public void handleMessage(SoapMessage message) throws Fault {
        logger.info("Validating message signature");
        
        try {
            Document doc = (Document) message.getContent(org.w3c.dom.Node.class);
            if (doc != null) {
                extractAndValidateSignature(doc);
            }
        } catch (Exception e) {
            logger.severe("Signature validation failed: " + e.getMessage());
            throw new Fault(e);
        }
    }
    
    private void extractAndValidateSignature(Document doc) {
        Element root = doc.getDocumentElement();
        
        NodeList securityHeaders = root.getElementsByTagNameNS(
            "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd", 
            "Security"
        );
        
        if (securityHeaders.getLength() > 0) {
            Element security = (Element) securityHeaders.item(0);
            NodeList signatures = security.getElementsByTagNameNS(
                "http://www.w3.org/2000/09/xmldsig#", 
                "Signature"
            );
            
            if (signatures.getLength() > 0) {
                logger.info("Found " + signatures.getLength() + " signature(s) in message");
            } else {
                logger.warning("No signature found in security header");
            }
        }
    }
}

// SOAPMessageParser.java
package com.bank.ws.security;

import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.NodeList;

import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import java.io.ByteArrayInputStream;
import java.util.ArrayList;
import java.util.List;
import java.util.logging.Logger;

public class SOAPMessageParser {
    
    private static final Logger logger = Logger.getLogger(SOAPMessageParser.class.getName());
    
    public Document parseSOAPMessage(String soapMessage) throws Exception {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        factory.setNamespaceAware(true);
        DocumentBuilder builder = factory.newDocumentBuilder();
        
        return builder.parse(new ByteArrayInputStream(soapMessage.getBytes()));
    }
    
    public List<Element> extractSignedElements(Document doc) {
        List<Element> signedElements = new ArrayList<>();
        
        NodeList references = doc.getElementsByTagNameNS(
            "http://www.w3.org/2000/09/xmldsig#", 
            "Reference"
        );
        
        for (int i = 0; i < references.getLength(); i++) {
            Element reference = (Element) references.item(i);
            String uri = reference.getAttribute("URI");
            
            if (uri != null && uri.startsWith("#")) {
                String id = uri.substring(1);
                Element signedElement = findElementById(doc, id);
                if (signedElement != null) {
                    signedElements.add(signedElement);
                    logger.info("Found signed element with ID: " + id);
                }
            }
        }
        
        return signedElements;
    }
    
    private Element findElementById(Document doc, String id) {
        NodeList allElements = doc.getElementsByTagName("*");
        for (int i = 0; i < allElements.getLength(); i++) {
            Element element = (Element) allElements.item(i);
            String elementId = element.getAttribute("wsu:Id");
            if (elementId == null || elementId.isEmpty()) {
                elementId = element.getAttribute("Id");
            }
            if (id.equals(elementId)) {
                return element;
            }
        }
        return null;
    }
    
    public Element getSOAPBody(Document doc) {
        NodeList bodyList = doc.getElementsByTagNameNS(
            "http://schemas.xmlsoap.org/soap/envelope/", 
            "Body"
        );
        
        if (bodyList.getLength() > 0) {
            return (Element) bodyList.item(0);
        }
        
        bodyList = doc.getElementsByTagNameNS(
            "http://www.w3.org/2003/05/soap-envelope", 
            "Body"
        );
        
        if (bodyList.getLength() > 0) {
            return (Element) bodyList.item(0);
        }
        
        return null;
    }
}

// XMLSignatureVerifier.java
package com.bank.ws.security;

import org.apache.xml.security.Init;
import org.apache.xml.security.signature.XMLSignature;
import org.apache.xml.security.keys.KeyInfo;
import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.NodeList;

import java.io.FileInputStream;
import java.security.KeyStore;
import java.security.cert.X509Certificate;
import java.util.logging.Logger;

public class XMLSignatureVerifier {
    
    private static final Logger logger = Logger.getLogger(XMLSignatureVerifier.class.getName());
    private KeyStore keyStore;
    
    static {
        Init.init();
    }
    
    public XMLSignatureVerifier(String keystorePath, String keystorePassword) throws Exception {
        keyStore = KeyStore.getInstance("JKS");
        try (FileInputStream fis = new FileInputStream(keystorePath)) {
            keyStore.load(fis, keystorePassword.toCharArray());
        }
    }
    
    public boolean verifySignature(Document doc) throws Exception {
        NodeList signatureNodes = doc.getElementsByTagNameNS(
            "http://www.w3.org/2000/09/xmldsig#", 
            "Signature"
        );
        
        if (signatureNodes.getLength() == 0) {
            logger.warning("No signature found in document");
            return false;
        }
        
        Element signatureElement = (Element) signatureNodes.item(0);
        XMLSignature signature = new XMLSignature(signatureElement, "");
        
        KeyInfo keyInfo = signature.getKeyInfo();
        X509Certificate cert = keyInfo.getX509Certificate();
        
        if (cert != null) {
            boolean valid = signature.checkSignatureValue(cert);
            logger.info("Signature validation result: " + valid);
            return valid;
        } else {
            logger.warning("No certificate found in signature");
            return false;
        }
    }
    
    public boolean verifySignatureWithKeystore(Document doc, String alias) throws Exception {
        NodeList signatureNodes = doc.getElementsByTagNameNS(
            "http://www.w3.org/2000/09/xmldsig#", 
            "Signature"
        );
        
        if (signatureNodes.getLength() == 0) {
            logger.warning("No signature found in document");
            return false;
        }
        
        Element signatureElement = (Element) signatureNodes.item(0);
        XMLSignature signature = new XMLSignature(signatureElement, "");
        
        X509Certificate cert = (X509Certificate) keyStore.getCertificate(alias);
        
        if (cert != null) {
            boolean valid = signature.checkSignatureValue(cert);
            logger.info("Signature validation with keystore result: " + valid);
            return valid;
        } else {
            logger.warning("Certificate not found for alias: " + alias);
            return false;
        }
    }
}

