package com.bank.ws;

import org.apache.cxf.Bus;
import org.apache.cxf.bus.spring.SpringBusFactory;
import org.apache.cxf.jaxws.JaxWsServerFactoryBean;
import org.apache.cxf.ws.security.wss4j.WSS4JInInterceptor;
import org.apache.cxf.ws.security.wss4j.WSS4JOutInterceptor;
import org.apache.wss4j.dom.handler.WSHandlerConstants;
import com.bank.ws.security.SignatureValidationInterceptor;

import java.util.HashMap;
import java.util.Map;
import java.util.logging.Logger;

public class BankingServicePublisher {
    
    private static final Logger logger = Logger.getLogger(BankingServicePublisher.class.getName());
    
    public static void main(String[] args) {
        logger.info("Starting Banking Web Service...");
        
        SpringBusFactory factory = new SpringBusFactory();
        Bus bus = factory.createBus();
        
        JaxWsServerFactoryBean serverFactory = new JaxWsServerFactoryBean();
        serverFactory.setBus(bus);
        serverFactory.setServiceClass(BankingService.class);
        serverFactory.setAddress("http://localhost:8080/banking");
        serverFactory.setServiceBean(new BankingServiceImpl());
        
        Map<String, Object> inProps = new HashMap<>();
        inProps.put(WSHandlerConstants.ACTION, WSHandlerConstants.SIGNATURE);
        inProps.put(WSHandlerConstants.SIG_PROP_FILE, "server-crypto.properties");
        inProps.put(WSHandlerConstants.PW_CALLBACK_CLASS, "com.bank.ws.security.ServerPasswordCallback");
        
        WSS4JInInterceptor wssIn = new WSS4JInInterceptor(inProps);
        serverFactory.getInInterceptors().add(wssIn);
        serverFactory.getInInterceptors().add(new SignatureValidationInterceptor());
        
        Map<String, Object> outProps = new HashMap<>();
        outProps.put(WSHandlerConstants.ACTION, WSHandlerConstants.SIGNATURE);
        outProps.put(WSHandlerConstants.USER, "server");
        outProps.put(WSHandlerConstants.SIG_PROP_FILE, "server-crypto.properties");
        outProps.put(WSHandlerConstants.PW_CALLBACK_CLASS, "com.bank.ws.security.ServerPasswordCallback");
        outProps.put(WSHandlerConstants.SIG_KEY_ID, "DirectReference");
        
        WSS4JOutInterceptor wssOut = new WSS4JOutInterceptor(outProps);
        serverFactory.getOutInterceptors().add(wssOut);
        
        serverFactory.create();
        
        logger.info("Banking Web Service started successfully at http://localhost:8080/banking");
        logger.info("WSDL available at http://localhost:8080/banking?wsdl");
    }
}

